import{_ as a,o,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Tiempos del Navegador","description":"","frontmatter":{},"headers":[],"relativePath":"es/configuration/browser-timings.md","filePath":"es/configuration/browser-timings.md"}'),r={name:"es/configuration/browser-timings.md"};function n(l,e,d,s,c,m){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="tiempos-del-navegador" tabindex="-1"><i class="ph ph-clock-countdown"></i> Tiempos del Navegador <a class="header-anchor" href="#tiempos-del-navegador" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-clock-countdown&quot;&gt;&lt;/i&gt; Tiempos del Navegador&quot;">​</a></h1><p>Esta página detalla las limitaciones técnicas de la arquitectura WebGL que atañen al parámetro <code>Application.targetFrameRate</code>.</p><p>Al compilar un proyecto de Unity para WebGL, el parámetro <code>Application.targetFrameRate</code> no solo modifica el límite de fotogramas interno del motor, sino que también altera la <strong>API base del navegador</strong> a través de la cual se ejecuta el bucle principal.</p><h2 id="sin-limite-uncapped-requestanimationframe" tabindex="-1">Sin Límite (Uncapped) (requestAnimationFrame) <a class="header-anchor" href="#sin-limite-uncapped-requestanimationframe" aria-label="Permalink to &quot;Sin Límite (Uncapped) (requestAnimationFrame)&quot;">​</a></h2><p>Si eliminas el límite de velocidad de fotogramas (dependiendo de la versión de Unity, estableciendo <code>Application.targetFrameRate</code> en <code>-1</code> o <code>0</code>), el compilador Emscripten vinculará el bucle principal de Unity directamente a la API del navegador <code>window.requestAnimationFrame</code>.</p><ul><li><strong>Ventajas:</strong> Es el método de renderizado más nativo, fluido y preciso en la web. El navegador sincronizará automáticamente la llamada con la tasa de refresco del monitor del jugador (VSync).</li><li><strong>Análisis:</strong> Las métricas de <code>cpuMainThreadFrameTime</code> (leídas por WebAP) reflejarán el tiempo <strong>real</strong> que la CPU empleó calculando física y scripts.</li></ul><h2 id="limite-artificial-settimeout" tabindex="-1">Límite Artificial (setTimeout) <a class="header-anchor" href="#limite-artificial-settimeout" aria-label="Permalink to &quot;Límite Artificial (setTimeout)&quot;">​</a></h2><p>Si fuerzas estrictamente una velocidad de fotogramas (por ejemplo, <code>Application.targetFrameRate = 30</code>), Emscripten se verá obligado a abandonar <code>requestAnimationFrame</code>. En su lugar, utilizará la API <code>setTimeout()</code> o complejas combinaciones de temporizadores internos para retrasar artificialmente el bucle.</p><div class="warning custom-block"><p class="custom-block-title">Distorsión de las Métricas de CPU (La Trampa de Emscripten)</p><p>Los temporizadores artificiales introducen una enorme discrepancia al medir el tiempo de la CPU. El procesador puede concluir todos los cálculos de la lógica del juego en un rápido tiempo de 5 ms y pasar a inactividad, pero la corrutina <code>WaitForEndOfFrame</code> no se reanudará hasta que expire el temporizador de <code>setTimeout</code>.</p><p><strong>Como resultado:</strong> El <code>FrameTimingManager</code> registrará este tiempo de espera dentro de los tiempos de la CPU. El analizador (y el Tracker de WebAP) deducirán que tienes un <em>Cuello de Botella de CPU (CPU Bottleneck)</em>, incluso si el procesador está funcionalmente inactivo y los fotogramas simplemente están esperando al temporizador del navegador.</p></div><h2 id="estrategia-de-configuracion-correcta" tabindex="-1">Estrategia de Configuración Correcta <a class="header-anchor" href="#estrategia-de-configuracion-correcta" aria-label="Permalink to &quot;Estrategia de Configuración Correcta&quot;">​</a></h2><p>Para el funcionamiento óptimo de Web Adaptive Performance en el navegador:</p><ol><li><strong>No uses <code>Application.targetFrameRate</code></strong>. Déjalo en <code>-1</code> (sin límite).</li><li>Especifica tu FPS deseado en la configuración del plugin (<code>Target Min FPS = 60</code>). WebAP utilizará ese valor no como un límite estricto, sino como la base para tomar decisiones sobre la calidad de renderizado.</li></ol>',12)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
